import heapq
class Solution:
    def minCosts(self, cost):
        n = len(cost)
        INF = float('inf')
        dist = [INF] * (n + 1)
        dist[n] = 0
        heap = [(0, n)]
        visited = [False] * (n + 1)
        result = [INF] * n
        while heap:
            d, u = heapq.heappop(heap)
            if visited[u]:
                continue
            visited[u] = True
            if u < n:
                result[u] = d
            for v in range(n):
                if v == u:
                    continue
                w = cost[v] if v < u else 0
                nd = d + w
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(heap, (nd, v))
        return result

